#ifndef SRC_LIB_WIFI_CONFIG_PORTAL_PAGE_GENERATED_H
#define SRC_LIB_WIFI_CONFIG_PORTAL_PAGE_GENERATED_H

static const char kWifiConfigPortalHtmlTemplate[] = "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>{{TITLE}}</title>\n  <style>\n:root{color-scheme:light;--bg:#eef2f5;--panel:#fff;--ink:#17202a;--muted:#5d6875;--line:#d8e0e8;--accent:#0f766e;--accent-2:#2457a6;--danger:#b42318;}\n    *{box-sizing:border-box;}\n    body{margin:0;background:var(--bg);color:var(--ink);font-family:Arial,Helvetica,sans-serif;font-size:15px;}\n    .shell{max-width:1040px;margin:0 auto;padding:20px;}\n    .topbar{display:flex;align-items:flex-start;justify-content:space-between;gap:16px;margin-bottom:14px;}\n    h1{margin:0;font-size:26px;line-height:1.18;letter-spacing:0;}\n    .sub{margin:6px 0 0;color:var(--muted);font-size:14px;}\n    .language{margin-top:12px;}\n    .language .lang-label{display:block;margin:0 0 6px;font-weight:700;font-size:13px;}\n    .language .lang-radio{display:flex;gap:14px;flex-wrap:wrap;}\n    .language .lang-radio label{display:inline-flex;align-items:center;margin:0;font-weight:400;font-size:14px;cursor:pointer;}\n    input[type=radio]{width:auto;min-height:0;margin-right:6px;}\n    .status{display:grid;grid-template-columns:repeat(2,minmax(150px,1fr));gap:8px;min-width:320px;}\n    .status div{background:var(--panel);border:1px solid var(--line);border-radius:8px;padding:10px 12px;}\n    .status span{display:block;color:var(--muted);font-size:12px;margin-bottom:3px;}\n    .mono{font-family:Consolas,monospace;}\n    .nav{display:flex;gap:8px;margin:0 0 14px;border-bottom:1px solid var(--line);}\n    .nav a{display:inline-block;padding:10px 12px;text-decoration:none;color:var(--muted);border-bottom:3px solid transparent;font-weight:700;}\n    .nav a.active{color:var(--accent);border-bottom-color:var(--accent);}\n    .panel{background:var(--panel);border:1px solid var(--line);border-radius:8px;padding:18px;margin-bottom:14px;}\n    .section-head{display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:12px;}\n    h2{margin:0;font-size:17px;letter-spacing:0;}\n    .hint{color:var(--muted);font-size:13px;}\n    .grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px 16px;}\n    label{display:block;margin:0 0 6px;font-weight:700;font-size:13px;}\n    input,select{width:100%;min-height:40px;padding:9px 10px;border:1px solid #c5ced8;border-radius:6px;font-size:15px;background:#fff;color:var(--ink);}\n    input[type=checkbox]{width:auto;min-height:0;margin-right:8px;}\n    .row{display:flex;gap:10px;align-items:center;flex-wrap:nowrap;}\n    .row select{flex:1;min-width:220px;width:auto;}\n    .row input{flex:1;min-width:0;width:auto;}\n    .icon-btn{flex:0 0 auto;min-height:40px;width:44px;padding:0;font-size:18px;line-height:1;}\n    .span-2{grid-column:1/-1;}\n    .actions{display:flex;gap:10px;align-items:center;justify-content:flex-end;flex-wrap:wrap;margin-top:16px;}\n    button,.button{display:inline-flex;align-items:center;justify-content:center;min-height:40px;padding:10px 14px;border:0;border-radius:6px;background:var(--accent);color:#fff;font-size:14px;font-weight:700;text-decoration:none;cursor:pointer;}\n    .button.secondary,button.secondary{background:#e8edf3;color:#17202a;border:1px solid var(--line);}\n    .btn-small{min-height:36px;padding:8px 11px;}\n    .notice{border-left:4px solid var(--accent-2);padding:10px 12px;background:#edf4ff;color:#25364c;border-radius:4px;margin:0 0 14px;}\n    .footer-links{display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-top:10px;}\n    .footer-links a{color:var(--accent-2);font-weight:700;text-decoration:none;}\n    .subpanel{grid-column:1/-1;border:1px solid var(--line);border-radius:8px;padding:12px;background:#f8fafc;}\n    .subpanel h3{margin:0 0 12px;font-size:15px;letter-spacing:0;}\n    .subgrid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px 16px;}\n    .group-label{border-top:1px solid var(--line);padding-top:12px;margin-top:2px;color:var(--accent-2);font-size:13px;font-weight:700;}\n    .subgrid>.group-label:first-child{border-top:0;padding-top:0;margin-top:0;}\n    .eq-panel{border:1px solid var(--line);border-radius:8px;padding:12px;background:#f8fafc;}\n    .eq-control{margin:12px 0;}\n    .eq-row{display:grid;grid-template-columns:minmax(0,1fr) 170px;gap:12px;align-items:center;}\n    input.eq-slider{padding:0;min-height:32px;}\n    input.eq-value{min-height:36px;font-size:13px;}\n    input.auto-slider{padding:0;min-height:32px;}\n    .item-form{margin:0;}\n    .item-form .actions{margin-top:8px;}\n    @media(max-width:760px){\n      .shell{padding:14px;}\n      .topbar{display:block;}\n      .status{grid-template-columns:1fr;min-width:0;margin-top:12px;}\n      .nav{overflow-x:auto;gap:4px;padding-bottom:2px;}\n      .nav a{flex:0 0 auto;padding:10px 9px;font-size:13px;white-space:nowrap;}\n      .panel{padding:14px;}\n      .section-head{display:block;}\n      .section-head .hint{display:block;margin-top:5px;}\n      .grid{grid-template-columns:1fr;}\n      .subgrid{grid-template-columns:1fr;}\n      .subpanel{padding:10px;}\n      .group-label{padding-top:10px;}\n      .span-2{grid-column:auto;}\n      .eq-row{grid-template-columns:1fr;}\n      .eq-control{margin:10px 0;}\n      input.eq-value{font-size:12px;}\n      .actions{justify-content:stretch;}\n      button,.button{width:100%;}\n    }\n\n</style>\n</head>\n<body>\n  <main class=\"shell\">\n    <div class=\"topbar\">\n      <div>\n        <h1 data-i18n=\"{{HEADLINE_KEY}}\">{{HEADLINE}}</h1>\n        <p class=\"sub\" data-i18n=\"{{INTRO_KEY}}\">{{INTRO}}</p>\n        <div class=\"language\">\n          <span class=\"lang-label\" data-i18n=\"language\">Language</span>\n          <div id=\"language-select\" class=\"lang-radio\">\n            <label><input type=\"radio\" name=\"lang\" value=\"en\">English</label>\n            <label><input type=\"radio\" name=\"lang\" value=\"zh\">\u4e2d\u6587</label>\n          </div>\n        </div>\n      </div>\n      <div class=\"status\">\n        <div><span data-i18n=\"configAp\">Config AP</span><strong class=\"mono\">{{AP_IP}}</strong></div>\n        <div><span data-i18n=\"stationIp\">Station IP</span><strong class=\"mono\">{{STA_IP}}</strong></div>\n      </div>\n    </div>\n\n    <nav class=\"nav\">\n      <a class=\"{{NETWORK_ACTIVE}}\" href=\"/\" data-i18n=\"wifiConfig\">WiFi Config</a>\n      <a class=\"{{DEVICE_ACTIVE}}\" href=\"/nrl\" data-i18n=\"nrlConfig\">NRL Config</a>\n      <a class=\"{{AUDIO_ACTIVE}}\" href=\"/audio\" data-i18n=\"audioSettings\">Audio Settings</a>\n      <a href=\"/update\" data-i18n=\"firmwareUpdate\">Firmware Update</a>\n    </nav>\n\n    <p class=\"notice\" data-i18n=\"bootNotice\">Hold BOOT for 5 seconds after startup to reset WiFi and server settings.</p>\n    <p class=\"sub\"><span data-i18n=\"firmwareVersion\">Firmware version</span> <span class=\"mono\">{{VERSION}}</span></p>\n\n    {{FORM_SECTIONS}}\n    <div class=\"footer-links\">{{FOOTER}}</div>\n  </main>\n  <script>\nconst translations = {\n      en: {\n        language: 'Language',\n        wifiConfig: 'WiFi Config',\n        nrlConfig: 'NRL Config',\n        audioSettings: 'Audio Settings',\n        firmwareUpdate: 'Firmware Update',\n        configAp: 'Config AP',\n        stationIp: 'Station IP',\n        bootNotice: 'Hold BOOT for 5 seconds after startup to reset WiFi and server settings.',\n        firmwareVersion: 'Firmware version',\n        wifiHeadline: 'WiFi Config',\n        wifiIntro: 'Set the WiFi network the device should join.',\n        nrlHeadline: 'NRL Config',\n        nrlIntro: 'Set server address and radio identity.',\n        audioHeadline: 'Audio Settings',\n        audioIntro: 'Set ES8311 output, volume, DRC, and EQ.',\n        wifiAppliedHeadline: 'WiFi Saved',\n        wifiAppliedIntro: 'WiFi settings were saved.',\n        wifiErrorHeadline: 'WiFi Save Failed',\n        wifiErrorIntro: 'Check the WiFi name and password.',\n        nrlAppliedHeadline: 'NRL Saved',\n        nrlAppliedIntro: 'NRL, server, and audio settings were saved.',\n        nrlErrorHeadline: 'NRL Save Failed',\n        nrlErrorIntro: 'Check server address, port, channel, callsign, SSID, and audio values.',\n        network: 'Network',\n        scanIdle: 'Click Scan to find nearby WiFi networks.',\n        wifiSsid: 'WiFi SSID',\n        wifiPassword: 'WiFi Password',\n        nearbyWifi: 'Nearby WiFi',\n        selectWifi: 'Select detected WiFi...',\n        scan: 'Scan',\n        server: 'Server',\n        serverHost: 'Server Host / IP',\n        serverPort: 'Server Port',\n        saveWifi: 'Save WiFi Config',\n        radio: 'Radio',\n        channel: 'Channel (0-7)',\n        callsign: 'Callsign',\n        callsignSsid: 'Callsign SSID',\n        hpDrive: 'ES8311 HP Drive',\n        hpDriveText: 'Enable headphone output drive (REG13 HPSW)',\n        audio: 'Audio',\n        micVolume: 'Mic Volume (0-255)',\n        lineOutVolume: 'Line Out Volume (0-255)',\n        saveNrl: 'Save NRL Config',\n        scanning: 'Scanning...',\n        foundPrefix: 'Found ',\n        foundSuffix: ' WiFi networks',\n        noneFound: 'No WiFi networks found',\n        scanFailed: 'Scan failed',\n        saveItem: 'Save'\n      },\n      zh: {\n        language: '\u8bed\u8a00',\n        wifiConfig: 'WiFi\u914d\u7f6e',\n        nrlConfig: 'NRL\u914d\u7f6e',\n        audioSettings: '\u97f3\u9891\u8bbe\u7f6e',\n        firmwareUpdate: '\u56fa\u4ef6\u5347\u7ea7',\n        configAp: '\u914d\u7f6e\u70ed\u70b9',\n        stationIp: '\u8054\u7f51\u5730\u5740',\n        bootNotice: '\u5f00\u673a\u540e\u6309\u4f4f BOOT 5 \u79d2\u53ef\u91cd\u7f6e WiFi \u548c\u670d\u52a1\u5668\u8bbe\u7f6e\u3002',\n        firmwareVersion: '\u56fa\u4ef6\u7248\u672c',\n        wifiHeadline: 'WiFi\u914d\u7f6e',\n        wifiIntro: '\u8bbe\u7f6e\u8bbe\u5907\u8981\u8fde\u63a5\u7684 WiFi \u7f51\u7edc\u3002',\n        nrlHeadline: 'NRL\u914d\u7f6e',\n        nrlIntro: '\u8bbe\u7f6e\u670d\u52a1\u5668\u5730\u5740\u548c\u7535\u53f0\u8eab\u4efd\u3002',\n        audioHeadline: '\u97f3\u9891\u8bbe\u7f6e',\n        audioIntro: '\u8bbe\u7f6e ES8311 \u8f93\u51fa\u3001\u97f3\u91cf\u3001DRC \u548c EQ\u3002',\n        wifiAppliedHeadline: 'WiFi\u5df2\u4fdd\u5b58',\n        wifiAppliedIntro: 'WiFi \u8bbe\u7f6e\u5df2\u4fdd\u5b58\u3002',\n        wifiErrorHeadline: 'WiFi\u4fdd\u5b58\u5931\u8d25',\n        wifiErrorIntro: '\u8bf7\u68c0\u67e5 WiFi \u540d\u79f0\u548c\u5bc6\u7801\u3002',\n        nrlAppliedHeadline: 'NRL\u5df2\u4fdd\u5b58',\n        nrlAppliedIntro: 'NRL\u3001\u670d\u52a1\u5668\u548c\u97f3\u9891\u8bbe\u7f6e\u5df2\u4fdd\u5b58\u3002',\n        nrlErrorHeadline: 'NRL\u4fdd\u5b58\u5931\u8d25',\n        nrlErrorIntro: '\u8bf7\u68c0\u67e5\u670d\u52a1\u5668\u5730\u5740\u3001\u7aef\u53e3\u3001\u4fe1\u9053\u3001\u547c\u53f7\u3001SSID \u548c\u97f3\u9891\u6570\u503c\u3002',\n        network: '\u7f51\u7edc',\n        scanIdle: '\u70b9\u51fb\u626b\u63cf\u67e5\u627e\u9644\u8fd1 WiFi\u3002',\n        wifiSsid: 'WiFi\u540d\u79f0',\n        wifiPassword: 'WiFi\u5bc6\u7801',\n        nearbyWifi: '\u9644\u8fd1WiFi',\n        selectWifi: '\u9009\u62e9\u626b\u63cf\u5230\u7684 WiFi...',\n        scan: '\u626b\u63cf',\n        server: '\u670d\u52a1\u5668',\n        serverHost: '\u670d\u52a1\u5668\u5730\u5740 / IP',\n        serverPort: '\u670d\u52a1\u5668\u7aef\u53e3',\n        saveWifi: '\u4fdd\u5b58WiFi\u914d\u7f6e',\n        radio: '\u7535\u53f0',\n        channel: '\u4fe1\u9053 (0-7)',\n        callsign: '\u547c\u53f7',\n        callsignSsid: '\u547c\u53f7SSID',\n        hpDrive: 'ES8311\u8033\u673a\u9a71\u52a8',\n        hpDriveText: '\u542f\u7528\u8033\u673a\u8f93\u51fa\u9a71\u52a8 (REG13 HPSW)',\n        audio: '\u97f3\u9891',\n        micVolume: '\u9ea6\u514b\u98ce\u97f3\u91cf (0-255)',\n        lineOutVolume: '\u7ebf\u8def\u8f93\u51fa\u97f3\u91cf (0-255)',\n        saveNrl: '\u4fdd\u5b58NRL\u914d\u7f6e',\n        scanning: '\u6b63\u5728\u626b\u63cf...',\n        foundPrefix: '\u627e\u5230 ',\n        foundSuffix: ' \u4e2a WiFi \u7f51\u7edc',\n        noneFound: '\u6ca1\u6709\u627e\u5230 WiFi \u7f51\u7edc',\n        scanFailed: '\u626b\u63cf\u5931\u8d25',\n        saveItem: '\u4fdd\u5b58'\n      }\n    };\n\n    function currentLang() {\n      const saved = localStorage.getItem('nrl_lang');\n      if (saved === 'zh' || saved === 'en') return saved;\n      return navigator.language && navigator.language.toLowerCase().startsWith('zh') ? 'zh' : 'en';\n    }\n\n    function t(key) {\n      const lang = currentLang();\n      return (translations[lang] && translations[lang][key]) || translations.en[key] || key;\n    }\n\n    function applyLanguage(lang) {\n      localStorage.setItem('nrl_lang', lang);\n      document.documentElement.lang = lang === 'zh' ? 'zh-CN' : 'en';\n      document.querySelectorAll('input[name=\"lang\"]').forEach((r) => {\n        r.checked = (r.value === lang);\n      });\n      document.querySelectorAll('[data-i18n]').forEach((el) => {\n        const key = el.getAttribute('data-i18n');\n        if (translations[lang] && translations[lang][key]) {\n          el.textContent = translations[lang][key];\n        }\n      });\n      document.querySelectorAll('[data-i18n-title]').forEach((el) => {\n        const key = el.getAttribute('data-i18n-title');\n        if (translations[lang] && translations[lang][key]) {\n          el.title = translations[lang][key];\n        }\n      });\n    }\n\n    function syncDhcpFields() {\n      const dhcp = document.getElementById('wifi-dhcp-enabled');\n      if (!dhcp) return;\n      document.querySelectorAll('.wifi-static-field').forEach((input) => {\n        input.disabled = dhcp.checked;\n      });\n    }\n\n    function clampEqValue(value) {\n      const text = String(value).trim();\n      const n = text.toLowerCase().startsWith('0x') ? Number.parseInt(text.slice(2), 16) : Number(text);\n      if (!Number.isFinite(n)) return 0;\n      return Math.max(0, Math.min(1073741823, Math.round(n)));\n    }\n\n    function formatEqHex(value) {\n      return '0x' + clampEqValue(value).toString(16).toUpperCase().padStart(8, '0');\n    }\n\n    function syncEqValue(slider) {\n      const box = slider.parentElement.querySelector('.eq-value');\n      if (box) box.value = formatEqHex(slider.value);\n    }\n\n    function syncEqSlider(box) {\n      const slider = box.parentElement.querySelector('.eq-slider');\n      const value = clampEqValue(box.value);\n      box.value = formatEqHex(value);\n      if (slider) slider.value = value;\n    }\n\n    function submitEqSlider(slider) {\n      syncEqValue(slider);\n      const form = slider.form;\n      if (!form || form.dataset.submitting === '1') return;\n      form.dataset.submitting = '1';\n      if (form.requestSubmit) form.requestSubmit();\n      else form.submit();\n    }\n\n    function syncAutoSliderValue(slider) {\n      const box = slider.parentElement.querySelector('.eq-value');\n      if (box) box.value = slider.value;\n    }\n\n    function submitAutoSlider(slider) {\n      syncAutoSliderValue(slider);\n      const form = slider.form;\n      if (!form || form.dataset.submitting === '1') return;\n      form.dataset.submitting = '1';\n      if (form.requestSubmit) form.requestSubmit();\n      else form.submit();\n    }\n\n    function submitSwitch(input) {\n      const form = input.form;\n      if (!form || form.dataset.submitting === '1') return;\n      form.dataset.submitting = '1';\n      if (form.requestSubmit) form.requestSubmit();\n      else form.submit();\n    }\n\n    function saveScrollPosition() {\n      sessionStorage.setItem('nrl_config_scroll_y', String(window.scrollY || 0));\n    }\n\n    function restoreScrollPosition() {\n      const saved = sessionStorage.getItem('nrl_config_scroll_y');\n      if (saved === null) return;\n      sessionStorage.removeItem('nrl_config_scroll_y');\n      const y = Number(saved);\n      if (Number.isFinite(y)) {\n        requestAnimationFrame(() => window.scrollTo(0, y));\n      }\n    }\n\n    async function scanWifi() {\n      const status = document.getElementById('scan-status');\n      const select = document.getElementById('wifi-ssid-select');\n      status.textContent = t('scanning');\n      try {\n        const res = await fetch('/scan', {cache: 'no-store'});\n        if (!res.ok) throw new Error('scan failed');\n        const items = await res.json();\n        renderWifiOptions(select, items);\n        status.textContent = items.length ? (t('foundPrefix') + items.length + t('foundSuffix')) : t('noneFound');\n      } catch (e) {\n        status.textContent = t('scanFailed');\n      }\n    }\n\n    function renderWifiOptions(select, items) {\n      let foundSelected = false;\n      const selected = select ? select.value : '';\n      if (select) {\n        select.innerHTML = '';\n        const placeholder = document.createElement('option');\n        placeholder.value = '';\n        placeholder.textContent = t('selectWifi');\n        placeholder.setAttribute('data-i18n', 'selectWifi');\n        select.appendChild(placeholder);\n      }\n      if (!Array.isArray(items)) {\n        if (select) select.value = selected;\n        return;\n      }\n      items.forEach((item) => {\n        if (!item || !item.ssid) return;\n        const label = item.label || item.ssid;\n        if (select) {\n          const opt = document.createElement('option');\n          opt.value = item.ssid;\n          opt.textContent = label;\n          select.appendChild(opt);\n          if (item.ssid === selected) foundSelected = true;\n        }\n      });\n      if (select && selected && !foundSelected) {\n        const opt = document.createElement('option');\n        opt.value = selected;\n        opt.textContent = selected;\n        select.appendChild(opt);\n      }\n      if (select) select.value = selected;\n    }\n\n    applyLanguage(currentLang());\n    syncDhcpFields();\n    restoreScrollPosition();\n    document.querySelectorAll('form').forEach((form) => {\n      form.addEventListener('submit', saveScrollPosition);\n    });\n    document.querySelectorAll('input[name=\"lang\"]').forEach((r) => {\n      r.addEventListener('change', function () {\n        if (this.checked) applyLanguage(this.value);\n      });\n    });\n\n</script>\n</body>\n</html>\n";

#endif
